package com.example.enterprise.service;

import com.example.enterprise.domain.User;
import com.example.enterprise.domain.UserStatus;
import com.example.enterprise.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class UserService {

    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public User createUser(String fullName, String email) {
        if (userRepository.existsByEmailIgnoreCase(email)) {
            throw new IllegalArgumentException("Email already exists");
        }
        User u = new User();
        u.setFullName(fullName);
        u.setEmail(email);
        u.setStatus(UserStatus.ACTIVE);
        return userRepository.save(u);
    }

    @Transactional(readOnly = true)
    public User getUser(Long id) {
        return userRepository.findById(id).orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    @Transactional(readOnly = true)
    public List<User> listActiveUsers() {
        return userRepository.findByStatus(UserStatus.ACTIVE);
    }

    @Transactional
    public User disableUser(Long id) {
        User u = getUser(id);
        u.setStatus(UserStatus.DISABLED);
        return userRepository.save(u);
    }
}

