package com.example.enterprise.service;

import com.example.enterprise.domain.Transaction;
import com.example.enterprise.domain.TransactionStatus;
import com.example.enterprise.domain.User;
import com.example.enterprise.repository.TransactionRepository;
import com.example.enterprise.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.List;
import java.util.UUID;

@Service
public class TransactionService {

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public Transaction createTransaction(Long userId, BigDecimal amount, String currency) {
        User user = userRepository.findById(userId).orElseThrow(() -> new IllegalArgumentException("User not found"));

        Transaction t = new Transaction();
        t.setUser(user);
        t.setAmount(amount);
        t.setCurrency(currency);
        t.setStatus(TransactionStatus.PENDING);
        return transactionRepository.save(t);
    }

    @Transactional(readOnly = true)
    public Transaction getByExternalReference(UUID externalReference) {
        return transactionRepository.findByExternalReference(externalReference)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
    }

    @Transactional
    public Transaction markCompleted(UUID externalReference) {
        Transaction t = getByExternalReference(externalReference);
        t.setStatus(TransactionStatus.COMPLETED);
        return transactionRepository.save(t);
    }

    @Transactional
    public Transaction markFailed(UUID externalReference) {
        Transaction t = getByExternalReference(externalReference);
        t.setStatus(TransactionStatus.FAILED);
        return transactionRepository.save(t);
    }

    @Transactional(readOnly = true)
    public List<Transaction> listUserTransactions(Long userId) {
        return transactionRepository.findByUserId(userId);
    }
}

