package com.example.enterprise.api;

import com.example.enterprise.api.dto.CreateTransactionRequest;
import com.example.enterprise.domain.Transaction;
import com.example.enterprise.service.TransactionService;
import jakarta.validation.Valid;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.UUID;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {

    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    @PostMapping
    public Transaction create(@Valid @RequestBody CreateTransactionRequest req) {
        return transactionService.createTransaction(req.getUserId(), req.getAmount(), req.getCurrency());
    }

    @GetMapping("/{externalReference}")
    public Transaction get(@PathVariable UUID externalReference) {
        return transactionService.getByExternalReference(externalReference);
    }

    @PostMapping("/{externalReference}/complete")
    public Transaction complete(@PathVariable UUID externalReference) {
        return transactionService.markCompleted(externalReference);
    }

    @PostMapping("/{externalReference}/fail")
    public Transaction fail(@PathVariable UUID externalReference) {
        return transactionService.markFailed(externalReference);
    }

    @GetMapping("/user/{userId}")
    public List<Transaction> listUser(@PathVariable Long userId) {
        return transactionService.listUserTransactions(userId);
    }
}

